import { useState, useEffect } from "react";

function App() {
  const [tarefa, setTarefa] = useState("");

  const [lista, setLista] = useState(() => {
    const tarefasSalvas = localStorage.getItem("tarefas");
    return tarefasSalvas ? JSON.parse(tarefasSalvas) : [];
  });

  useEffect(() => {
    localStorage.setItem("tarefas", JSON.stringify(lista));
  }, [lista]);

  function adicionarTarefa() {
    if (tarefa.trim() === "") return;

    const novaTarefa = {
      texto: tarefa,
      concluida: false
    };

    setLista([...lista, novaTarefa]);
    setTarefa("");
  }

  function removerTarefa(index) {
    const novaLista = lista.filter((_, i) => i !== index);
    setLista(novaLista);
  }

  function toggleTarefa(index) {
    const novaLista = lista.map((item, i) => {
      if (i === index) {
        return { ...item, concluida: !item.concluida };
      }
      return item;
    });

    setLista(novaLista);
  }

  return (
    <div style={styles.container}>
      <h1>To-Do List</h1>

      <div style={styles.inputArea}>
        <input
          style={styles.input}
          value={tarefa}
          onChange={(e) => setTarefa(e.target.value)}
          placeholder="Digite uma tarefa"
        />

        <button style={styles.addButton} onClick={adicionarTarefa}>
          Adicionar
        </button>
      </div>

      <ul style={styles.lista}>
        {lista.map((item, index) => (
          <li key={index} style={styles.item}>

            <span
              style={{
                ...styles.texto,
                textDecoration: item.concluida ? "line-through" : "none"
              }}
            >
              {item.texto}
            </span>

            <div style={styles.actions}>
              <button
                style={styles.checkButton}
                onClick={() => toggleTarefa(index)}
              >
                ✔
              </button>

              <button
                style={styles.deleteButton}
                onClick={() => removerTarefa(index)}
              >
                X
              </button>
            </div>

          </li>
        ))}
      </ul>
    </div>
  );
}

const styles = {
  container: {
    maxWidth: 400,
    margin: "50px auto",
    textAlign: "center",
    fontFamily: "Arial"
  },
  inputArea: {
    display: "flex",
    gap: 10,
    marginBottom: 20
  },
  input: {
    flex: 1,
    padding: 10,
    fontSize: 16
  },
  addButton: {
    padding: "10px 15px",
    cursor: "pointer"
  },
  lista: {
    listStyle: "none",
    padding: 0
  },
  item: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: 10,
    borderBottom: "1px solid #ccc"
  },
  texto: {},
  actions: {
    display: "flex",
    gap: 5
  },
  checkButton: {
    background: "green",
    color: "#fff",
    border: "none",
    padding: "5px 8px",
    cursor: "pointer"
  },
  deleteButton: {
    background: "red",
    color: "#fff",
    border: "none",
    padding: "5px 10px",
    cursor: "pointer"
  }
};

export default App;
